        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), v = f._language == 'v', g = f.getItem('d83')._controlBehavior;
var l1 = g._getColumnOrder('stt_rec_hd');
var e1 = (v ? 'Thông tin nhà cung cấp của phiếu nhập điều chỉnh phải giống với hóa đơn.' : 'Purchase Adjustment should have same supplier information as Invoice.');

var t = f.getItemValue('ma_kh');
for (var i = 1; i <= g._rowCount; i++) {
  var v1 = (g._getItemValue(i, l1) != '');
  if (v1) {
    var u = g._getItem(i, 1)._customerIdentity;
    if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
    if (t != u) {
      $func.hideWait(id);
      $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
      f._checked = false;
      break;
    }
  }
}
